import React from 'react';
import { Link } from 'react-router-dom';

const Navigation = () => {
  return (
    <nav className="navbar navbar-expand-lg navbar-dark bg-dark">
      <div className="container mt-1 mb-1">
        <Link className="navbar-brand" to='/movieshub/'>Movies<span className="text-primary">Hub</span></Link>
        <button className="navbar-toggler" type="button" data-bs-toggle="collapse" data-bs-target="#navbarSupportedContent" aria-controls="navbarSupportedContent" aria-expanded="false" aria-label="Toggle navigation">
          <span className="navbar-toggler-icon"></span>
        </button>
        <div className="collapse navbar-collapse" id="navbarSupportedContent">
          <ul className="navbar-nav ms-auto">
            <li className="nav-item ms-5">
              <Link className="nav-link" to='/movieshub/movie'>Movies</Link>
            </li>
            <li className="nav-item ms-5">
              <Link className="nav-link" to='/movieshub/tv'>TV Shows</Link>
            </li>
            <li className="nav-item ms-5">
              <Link className="nav-link" to='/movieshub/people'>People</Link>
            </li>
          </ul>
        </div>
      </div>
    </nav>
  )
}

export default Navigation
